INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.16.118','cb','cb.adi.16','ЧБ Ади 16.118',118,'মরেও না, আরো দেখি,—হাসে ক্ষণে ক্ষণে” ।
“এ পুরুষ পীর বা?”—সবেই ভাবে মনে ॥১১৮॥','маре о на̄, а̄ро декхи, — ха̄се кш̣ан̣е кш̣ан̣е’
‘е пуруш̣а пӣра ва̄?’ — сабеи бха̄ве мане',NULL,NULL),('cb.adi.16.119','cb','cb.adi.16','ЧБ Ади 16.119',119,'যবনসকল বলে,—“ওহে হরিদাস ! ।
তোমা’ হৈতে আমা’-সবার হইবেক নাশ ॥১১৯॥','йавана-сакала бале, — ‘охе харида̄са!
тома̄’ хаите а̄ма̄’-саба̄ра хаибека на̄ш́а',NULL,NULL),('cb.adi.16.120','cb','cb.adi.16','ЧБ Ади 16.120',120,'এত প্রহারেও প্রাণ না যায় তোমার ।
কাজী প্রাণ লইবেক আমা’-সবাকার” ॥১২০॥
হাসিয়া বলেন হরিদাস মহাশয় ।
“আমি জীলে তোমা’-সবার মন্দ যদি হয় ॥১২১॥
তবে আমি মরি,—এই দেখ বিদ্যমান” ।
এত বলি’ আবিষ্ট হইলা করি’ ধ্যান ॥১২২॥','эта праха̄ре о пра̄н̣а на̄ йа̄йа тома̄ра
ка̄джӣ пра̄н̣а лаибека а̄ма̄’ саба̄ка̄ра’
ха̄сийа̄ балена харида̄са маха̄ш́айа
‘а̄ми джӣле тома̄’ саба̄ра манда йади хайа
табе а̄ми мари, — йе декха видйама̄на’
эта бале’ а̄виш̣т̣а хаила̄ кари’ дхйа̄на',NULL,NULL),('cb.adi.16.123','cb','cb.adi.16','ЧБ Ади 16.123',123,'সর্ব্ব-শক্তি-সমন্বিত প্রভু-হরিদাস ।
হইলেন অচেষ্ট, কোথাও নাহি শ্বাস ॥১২৩॥','сарва-ш́акти-саманвита прабху-харида̄са
хаилена ачеш̣т̣а, котха̄ о на̄хи ш́ва̄са',NULL,NULL),('cb.adi.16.124','cb','cb.adi.16','ЧБ Ади 16.124',124,'দেখিয়া যবনগণ বিস্মিত হইল ।
মুলুকপতির দ্বারে লৈয়া ফেলাইল ॥১২৪॥','декхийа̄ йавана-ган̣а висмита хаила
мулука-патира два̄ре лаийа̄ пхела̄ила',NULL,NULL),('cb.adi.16.125','cb','cb.adi.16','ЧБ Ади 16.125',125,'“মাটি দেহ’ নিঞা” বলে মুলুকের পতি ।
কাজী কহে,—“তবে ত’ পাইবে ভাল-গতি ॥১২৫॥','‘ма̄т̣и деха’ нин̃а̄’ бале мулукера пати
ка̄джӣ кахе, — ‘табе та па̄ибе бха̄ла-гати',NULL,NULL),('cb.adi.16.126','cb','cb.adi.16','ЧБ Ади 16.126',126,'বড় হই’ যেন করিলেক নীচ-কর্ম্ম ।
অতএব ইহারে যুয়ায় হেন ধর্ম্ম ॥১২৬॥','бад̣а хаи’ йена карилека нӣча-карма
атаева иха̄ре йуйа̄йа хена дхарма',NULL,NULL),('cb.adi.16.127','cb','cb.adi.16','ЧБ Ади 16.127',127,'মাটি দিলে পরলোকে হইবেক ভাল ।
গাঙ্গে ফেল,—যেন দুঃখ পায় চিরকাল” ॥১২৭॥','ма̄т̣и диле паралоке хаибека бха̄ла
га̄н̇ге пхела, — йена дух̣кха па̄йа чирака̄ла',NULL,NULL),('cb.adi.16.128','cb','cb.adi.16','ЧБ Ади 16.128',128,'কাজীর বচনে সব ধরিয়া যবনে ।
গাঙ্গে ফেলাইতে সবে তোলে গিয়া তানে ॥১২৮॥','ка̄джӣра вачане саба дхарийа̄ йаване
га̄н̇ге пхела̄ите сабе толе гийа̄ та̄’не',NULL,NULL),('cb.adi.16.129','cb','cb.adi.16','ЧБ Ади 16.129',129,'গাঙ্গে নিতে তোলে যদি যবনসকল ।
বসিলেন হরিদাস হইয়া নিশ্চল ॥১২৯॥','га̄н̇ге ните толе йади йавана-сакала
василена харида̄са хаийа̄ ниш́чала',NULL,NULL),('cb.adi.16.130','cb','cb.adi.16','ЧБ Ади 16.130',130,'ধ্যানানন্দে বসিলা ঠাকুর হরিদাস ।
বিশ্বম্ভর দেহে আসি’ হৈলা পরকাশ ॥১৩০॥','дхйа̄на̄нанде васила̄ т̣ха̄кура харида̄са
виш́вамбхара дехе а̄си’ хаила̄ парака̄ш́а',NULL,NULL),('cb.adi.16.131','cb','cb.adi.16','ЧБ Ади 16.131',131,'বিশ্বম্ভর-অধিষ্ঠান হইল শরীরে ।
কার শক্তি আছে হরিদাসে নাড়িবারে? ॥ ১৩১॥','виш́вамбхара-адхиш̣т̣ха̄на хаила ш́арӣре
ка̄’ра ш́акти а̄чхе харида̄се на̄д̣иба̄ре?',NULL,NULL),('cb.adi.16.132','cb','cb.adi.16','ЧБ Ади 16.132',132,'মহা-বলবন্ত সব চতুর্দ্দিকে ঠেলে ।
মহা-স্তম্ভপ্রায় প্রভু আছেন নিশ্চলে ॥১৩২॥','маха̄-балаванта саба чатур-дике т̣хеле
маха̄-стамбха-пра̄йа прабху а̄чхена ниш́чале',NULL,NULL),('cb.adi.16.133','cb','cb.adi.16','ЧБ Ади 16.133',133,'কৃষ্ণানন্দ-সুধাসিন্ধু-মধ্যে হরিদাস ।
মগ্ন হই’ আছেন, বাহ্য নাহি পরকাশ ॥১৩৩॥','кр̣ш̣н̣а̄нанда-судха̄-синдху-мадхйе харида̄са
магна хаи’ а̄чхена, ба̄хйе на̄хи парака̄ш́а',NULL,NULL),('cb.adi.16.134','cb','cb.adi.16','ЧБ Ади 16.134',134,'কিবা অন্তরীক্ষে, কিবা পৃথ্বীতে, গঙ্গায় ।
না জানেন হরিদাস আছেন কোথায় ॥১৩৪॥','киба̄ антарӣкш̣е, киба̄ пр̣тхвӣте, ган̇га̄йа
на̄ джа̄нена харида̄са а̄чхена котха̄йа',NULL,NULL),('cb.adi.16.135','cb','cb.adi.16','ЧБ Ади 16.135',135,'প্রহ্লাদের যেহেন স্মরণ কৃষ্ণভক্তি ।
সেইমত হরিদাস-ঠাকুরের শক্তি ॥১৩৫॥','прахла̄дера йехена смаран̣а кр̣ш̣н̣а-бхакти
сеи-мата харида̄са т̣ха̄курера ш́акти',NULL,NULL),('cb.adi.16.136','cb','cb.adi.16','ЧБ Ади 16.136',136,'হরিদাসে এই সব কিছু চিত্র নহে ।
নিরবধি গৌরচন্দ্র যাঁহান হৃদয়ে ॥১৩৬॥
রাক্ষসের বন্ধনে যেহেন হনূমান্ ।
আপনে লইলা করি’ ব্রহ্মার সম্মান ॥১৩৭॥
এইমত হরিদাস যবন-প্রহার ।
জগতের শিক্ষা লাগি’ করিলা স্বীকার ॥১৩৮॥','харида̄се йе саба кичху читра нахе
ниравадхи гаурачандра йа̄н̇ха̄на хр̣дайе
ра̄кш̣асера бандхане йехена ханӯма̄н
а̄пане лаила̄ кари’ брахма̄ра сама̄на
эи-мата харида̄са йавана-праха̄ра
джагатера ш́икш̣а̄ ла̄ги’ карила̄ свика̄ра',NULL,NULL),('cb.adi.16.139','cb','cb.adi.16','ЧБ Ади 16.139',139,'“অশেষ দুর্গতি হয়, যদি যায় প্রাণ ।
তথাপি বদনে না ছাড়িব হরিনাম” ॥১৩৯॥','‘аш́еш̣а дургати хайа, йади йа̄йа пра̄н̣а
татха̄пи вадане на̄ чха̄д̣иба хари-на̄ма',NULL,NULL),('cb.adi.16.140','cb','cb.adi.16','ЧБ Ади 16.140',140,'অন্যথা গোবিন্দ-হেন রক্ষক থাকিতে ।
কার শক্তি আছে হরিদাসেরে লঙ্ঘিতে? ॥১৪০॥','анйатха̄ говинда-хена ракш̣ака тха̄ките
ка̄’ра ш́акти а̄чхе харида̄сере лан̇гхите?',NULL,NULL),('cb.adi.16.141','cb','cb.adi.16','ЧБ Ади 16.141',141,'হরিদাস-স্মরণেও এ দুঃখ সর্ব্বথা ।
খণ্ডে’ সেইক্ষণে, হরিদাসের কি কথা ॥১৪১॥','харида̄са-смаран̣е о э дух̣кха сарватха̄
кхан̣д̣е сеи-кш̣ан̣е, харида̄сера ки катха̄',NULL,NULL),('cb.adi.16.142','cb','cb.adi.16','ЧБ Ади 16.142',142,'সত্য সত্য হরিদাস—জগৎ-ঈশ্বর ।
চৈতন্যচন্দ্রের মহা-মুখ্য অনুচর ॥১৪২॥','сатйа сатйа харида̄са–джагат-ӣш́вара
чаитанйа-чандрера маха̄-мукхйа анучара',NULL,NULL),('cb.adi.16.143','cb','cb.adi.16','ЧБ Ади 16.143',143,'হেনমতে হরিদাস ভাসেন গঙ্গায় ।
ক্ষণেকে হইল বাহ্য ঈশ্বর-ইচ্ছায় ॥১৪৩॥','хена-мате харида̄са бха̄сена ган̇га̄йа
кш̣ан̣еке хаила ба̄хйа ӣш́вара-иччха̄йа',NULL,NULL),('cb.adi.16.144','cb','cb.adi.16','ЧБ Ади 16.144',144,'চৈতন্য পাইয়া হরিদাস-মহাশয় ।
তীরে আসি’ উঠিলেন পরানন্দময় ॥১৪৪॥','чаитанйа па̄ийа̄ харида̄са-маха̄ш́айа
тӣре а̄си’ ут̣хилена пара̄нанда-майа',NULL,NULL),('cb.adi.16.145','cb','cb.adi.16','ЧБ Ади 16.145',145,'সেইমতে আইলেন ফুলিয়া-নগরে ।
কৃষ্ণনাম বলিতে বলিতে উচ্চৈঃস্বরে ॥১৪৫॥','сеи-мате а̄илена пхулийа̄-нагаре
кр̣ш̣н̣а-на̄ма балите балите уччаих̣-сваре',NULL,NULL),('cb.adi.16.146','cb','cb.adi.16','ЧБ Ади 16.146',146,'দেখিয়া অদ্ভুসত-শক্তি সকল যবন ।
সবার খণ্ডিল হিংসা, ভাল হৈল মন ॥১৪৬॥','декхийа̄ адбхута-ш́акти сакала йавана
саба̄ра кхан̣д̣ила хим̇са̄, бха̄ла хаила мана',NULL,NULL),('cb.adi.16.147','cb','cb.adi.16','ЧБ Ади 16.147',147,'‘পীর’ জ্ঞান করি’ সবে কৈল নমস্কার ।
সকল যবনগণ পাইল নিস্তার ॥১৪৭॥','пӣра’ джн̃а̄на кари’ сабе каила намаска̄ра
сакала йавана-ган̣а па̄ила ниста̄ра',NULL,NULL),('cb.adi.16.148','cb','cb.adi.16','ЧБ Ади 16.148',148,'কতক্ষণে বাহ্য পাইলেন হরিদাস ।
মুলুকপতিরে চা’হি’ হৈল কৃপা-হাস ॥১৪৮॥','ката-кш̣ан̣е ба̄хйа па̄илена харида̄са
мулука-патире ча̄хи’ хаила кр̣па̄-ха̄са',NULL,NULL),('cb.adi.16.149','cb','cb.adi.16','ЧБ Ади 16.149',149,'সম্ভ্রমে মুলুকপতি যুড়ি’ দুই কর ।
বলিতে লাগিল কিছু বিনয়-উত্তর ॥১৪৯॥','самбхраме мулука-пати йуд̣и’ дуи кара
балите ла̄гила кичху винайа-уттара',NULL,NULL),('cb.adi.16.150','cb','cb.adi.16','ЧБ Ади 16.150',150,'“সত্য সত্য জানিলাঙ,—তুমি মহা-পীর ।
‘এক’-জ্ঞান তোমার সে হইয়াছে স্থির ॥১৫০॥','‘сатйа сатйа джа̄нила̄н̇а,–туми маха̄-пӣра
‘эка’-джн̃а̄на тома̄ра се хаийа̄чхе стхира',NULL,NULL),('cb.adi.16.151','cb','cb.adi.16','ЧБ Ади 16.151',151,'যোগী জ্ঞানী যত সব মুখে-মাত্র বলে ।
তুমি সে পাইলা সিদ্ধি মহা-কুতূহলে ॥১৫১॥','йогӣ джн̃а̄нӣ йата саба мукхе-ма̄тра бале
туми се па̄ила̄ сиддхи маха̄-кутӯхале',NULL,NULL),('cb.adi.16.152','cb','cb.adi.16','ЧБ Ади 16.152',152,'তোমারে দেখিতে মুই আইলুঁ এথারে ।
সব দোষ, মহাশয় ! ক্ষমিবা আমারে ॥১৫২॥','тома̄ре декхите муи а̄илун̇ этха̄ре
саба дош̣а, маха̄ш́айа! кш̣амиба̄ а̄ма̄ре',NULL,NULL),('cb.adi.16.153','cb','cb.adi.16','ЧБ Ади 16.153',153,'সকল তোমার সম,—শত্রু-মিত্র নাই ।
তোমা’ চিনে,—হেন জন ত্রিভুবনে নাই ॥১৫৩॥','сакала тома̄ра сама,–‘ш́атру-митра на̄и
тома̄’ чине, — хена джана трибхуване на̄и',NULL,NULL),('cb.adi.16.154','cb','cb.adi.16','ЧБ Ади 16.154',154,'চল তুমি, শুভ কর’ আপন-ইচ্ছায় ।
গঙ্গাতীরে থাক গিয়া-নির্জ্জন-গোফায় ॥১৫৪॥','чала туми, ш́убха кара’ а̄пана-иччха̄йа
ган̇га̄-тӣре тха̄ка гийа̄ нирджана-гопха̄йа',NULL,NULL),('cb.adi.16.155','cb','cb.adi.16','ЧБ Ади 16.155',155,'আপন-ইচ্ছায় তুমি থাক যথা-তথা ।
যে তোমার ইচ্ছা, তাই করহ সর্ব্বথা” ॥১৫৫॥','а̄пана-иччха̄йа туми тха̄ка йатха̄-татха̄
йе тома̄ра иччха̄, та̄и караха сарватха̄’',NULL,NULL),('cb.adi.16.156','cb','cb.adi.16','ЧБ Ади 16.156',156,'হরিদাস-ঠাকুরের চরণ দেখিলে ।
উত্তমের কি দায়, যবন দেখি’ ভুলে’ ॥১৫৬॥','харида̄са-т̣ха̄курера чаран̣а декхиле
уттамера ки да̄йа, йавана декхи’ бхуле’',NULL,NULL),('cb.adi.16.157','cb','cb.adi.16','ЧБ Ади 16.157',157,'এত ক্রোধে আনিলেক মারিবার তরে ।
‘পীর’ জ্ঞান করি’ আরো পা’য়ে পাছে ধরে ॥১৫৭॥','эта кродхе а̄нилека ма̄риба̄ра таре
‘пӣра’ — джн̃а̄на кари’ а̄ро па̄’йе па̄чхе дхаре',NULL,NULL),('cb.adi.16.158','cb','cb.adi.16','ЧБ Ади 16.158',158,'যবনেরে কৃপা-দৃষ্টি করিয়া প্রকাশ ।
ফুলিয়ায় আইলা ঠাকুর-হরিদাস ॥১৫৮॥
উচ্চ করি’ হরিনাম লইতে লইতে ।
